+import { describe, expect, it } from "vitest";
+import {
+  PasswordResetService,
+  type RateLimitStore
+} from "../src/password-reset";
+
+interface SharedCounter {
+  count: number;
+  windowStartedAt: number;
+}
+
+class DeferredWriteBackend {
+  readonly counters = new Map<string, SharedCounter>();
+  private readonly pendingWrites: Array<() => void> = [];
+
+  defer(write: () => void): void {
+    this.pendingWrites.push(write);
+  }
+
+  flush(): void {
+    for (const write of this.pendingWrites.splice(0)) {
+      write();
+    }
+  }
+}
+
+/**
+ * Models one process-local client performing a non-atomic read/check/write
+ * against a backend shared with other clients. Deferred writes make the
+ * otherwise timing-sensitive lost-update schedule deterministic.
+ */
+class NonAtomicDistributedRateLimitStore implements RateLimitStore {
+  constructor(private readonly backend: DeferredWriteBackend) {}
+
+  consume(identifier: string, limit: number, windowMs: number, now: number): boolean {
+    const counter = this.backend.counters.get(identifier);
+
+    if (!counter || now - counter.windowStartedAt >= windowMs) {
+      this.backend.defer(() => {
+        this.backend.counters.set(identifier, { count: 1, windowStartedAt: now });
+      });
+      return true;
+    }
+
+    if (counter.count >= limit) {
+      return false;
+    }
+
+    const nextCount = counter.count + 1;
+    this.backend.defer(() => {
+      this.backend.counters.set(identifier, {
+        count: nextCount,
+        windowStartedAt: counter.windowStartedAt
+      });
+    });
+    return true;
+  }
+}
+
+class AtomicBackend {
+  private readonly counters = new Map<string, SharedCounter>();
+
+  consume(identifier: string, limit: number, windowMs: number, now: number): boolean {
+    const counter = this.counters.get(identifier);
+
+    if (!counter || now - counter.windowStartedAt >= windowMs) {
+      this.counters.set(identifier, { count: 1, windowStartedAt: now });
+      return true;
+    }
+
+    if (counter.count >= limit) {
+      return false;
+    }
+
+    counter.count += 1;
+    return true;
+  }
+}
+
+class AtomicDistributedRateLimitStore implements RateLimitStore {
+  constructor(private readonly backend: AtomicBackend) {}
+
+  consume(identifier: string, limit: number, windowMs: number, now: number): boolean {
+    return this.backend.consume(identifier, limit, windowMs, now);
+  }
+}
+
+class FailingRateLimitStore implements RateLimitStore {
+  consume(): boolean {
+    throw new Error("shared rate-limit backend unavailable");
+  }
+}
+
+function requestFourResets(
+  createStore: () => RateLimitStore,
+  afterRequests: () => void = () => undefined
+): string[] {
+  const delivered: string[] = [];
+  const services = [0, 1].map(() => new PasswordResetService(
+    new Set(["alan@example.com"]),
+    (email) => delivered.push(email),
+    () => 1_000,
+    createStore()
+  ));
+
+  for (let index = 0; index < 4; index += 1) {
+    services[index % services.length]!.request(
+      "alan@example.com",
+      `203.0.113.${index}`
+    );
+  }
+  afterRequests();
+  return delivered;
+}
+
+describe("distributed RateLimitStore conformance", () => {
+  it("retains the deterministic lost-update proof for non-atomic clients", () => {
+    const backend = new DeferredWriteBackend();
+    const delivered = requestFourResets(
+      () => new NonAtomicDistributedRateLimitStore(backend),
+      () => backend.flush()
+    );
+
+    expect(delivered).toHaveLength(4);
+  });
+
+  it("keeps one three-delivery budget across independent atomic clients", () => {
+    const backend = new AtomicBackend();
+    const delivered = requestFourResets(
+      () => new AtomicDistributedRateLimitStore(backend)
+    );
+
+    expect(delivered).toHaveLength(3);
+  });
+
+  it("fails closed without changing the public response when the store fails", () => {
+    const delivered: string[] = [];
+    const service = new PasswordResetService(
+      new Set(["alan@example.com"]),
+      (email) => delivered.push(email),
+      () => 1_000,
+      new FailingRateLimitStore()
+    );
+
+    const knownResponse = service.request("alan@example.com", "198.51.100.1");
+    const unknownResponse = service.request("nobody@example.com", "198.51.100.2");
+
+    expect(knownResponse).toEqual(unknownResponse);
+    expect(delivered).toHaveLength(0);
+  });
+});
