+import { describe, expect, it } from "vitest";
+import { InMemoryRateLimitStore } from "../src/password-reset";
+
+describe("identifier fixed-window rollover", () => {
+  it("opens the next identifier budget at the exact window boundary", () => {
+    const limits = new InMemoryRateLimitStore();
+    const windowMs = 60_000;
+    const startedAt = 5_000;
+
+    expect(limits.consume("target@example.test", 1, windowMs, startedAt)).toBe(true);
+    expect(limits.consume("target@example.test", 1, windowMs, startedAt)).toBe(false);
+    expect(limits.consume("target@example.test", 1, windowMs, startedAt + windowMs)).toBe(true);
+  });
+
+  it("bounds storage and admits a new identifier after expired-key cleanup", () => {
+    const limits = new InMemoryRateLimitStore(2);
+    const windowMs = 60_000;
+    const startedAt = 5_000;
+
+    expect(limits.consume("first@example.test", 1, windowMs, startedAt)).toBe(true);
+    expect(limits.consume("second@example.test", 1, windowMs, startedAt)).toBe(true);
+    expect(limits.consume("third@example.test", 1, windowMs, startedAt)).toBe(false);
+    expect(limits.entryCount).toBe(2);
+
+    expect(limits.consume("third@example.test", 1, windowMs, startedAt + windowMs)).toBe(true);
+    expect(limits.entryCount).toBe(1);
+  });
+
+  it("allows at most one complete budget in each adjacent fixed window", () => {
+    const limits = new InMemoryRateLimitStore();
+    const limit = 3;
+    const windowMs = 60_000;
+
+    for (let index = 0; index < limit; index += 1) {
+      expect(limits.consume("target@example.test", limit, windowMs, 0)).toBe(true);
+    }
+    expect(limits.consume("target@example.test", limit, windowMs, windowMs - 1)).toBe(false);
+
+    for (let index = 0; index < limit; index += 1) {
+      expect(limits.consume("target@example.test", limit, windowMs, windowMs)).toBe(true);
+    }
+    expect(limits.consume("target@example.test", limit, windowMs, windowMs)).toBe(false);
+  });
+});

